const searchInput = document.getElementById('wiki-search');
const searchResults = document.getElementById('search-results');

function slugify(s) {
  return s.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
}

function highlight(text, q){
  if(!q) return text;
  try {
    const re = new RegExp('('+q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')+')','gi');
    return text.replace(re, '<mark>$1</mark>');
  } catch(e) { return text; }
}

function doSearch(q){
  q = q.trim().toLowerCase();
  if(!searchResults) return;
  if(!q || q.length < 1){ searchResults.classList.remove('open'); searchResults.innerHTML=''; return; }
  const results = SEARCH_INDEX.filter(e => 
    (e.t||'').toLowerCase().includes(q) || 
    (e.s||'').toLowerCase().includes(q) ||
    (e.c||'').toLowerCase().includes(q)
  ).slice(0,14);
  if(results.length===0){
    searchResults.innerHTML = `<div class="search-no-results">No results for "${q}"</div>`;
  } else {
    searchResults.innerHTML = results.map(r => `
      <a class="search-result-item" href="${r.u}">
        <div class="sr-title">${highlight(r.t, q)} <span style="opacity:.7"> ${r.i||''}</span></div>
        <div class="sr-path">${r.c||''}</div>
        <div class="sr-snippet">${highlight(r.s||'', q)}</div>
      </a>
    `).join('');
  }
  searchResults.classList.add('open');
}

if(searchInput){
  searchInput.addEventListener('input', e => doSearch(e.target.value));
  searchInput.addEventListener('focus', e => { if(e.target.value) doSearch(e.target.value); });
  document.addEventListener('click', e => {
    if(!e.target.closest('.search-wrap') && searchResults) searchResults.classList.remove('open');
  });
  searchInput.addEventListener('keydown', e => {
    if(e.key === 'Escape'){ if(searchResults) searchResults.classList.remove('open'); searchInput.blur(); }
  });
}

// Auto-inject IDs for search anchors (fruits, swords, melee styles, races, clans, bloodlines, codes)
(function addSearchAnchors(){
  const nameSelectors = '.fruit-name, .bloodline-name, .race-name, .clan-name, .sword-name, .melee-name, .style-name, .code-string';
  document.querySelectorAll(nameSelectors).forEach(el => {
    const name = el.textContent.trim();
    if(!name) return;
    const id = slugify(name);
    // put id on the closest tr, or on the element itself
    const tr = el.closest('tr');
    const target = tr || el;
    if(target && !target.id) target.id = id;
  });
})();

// Auto TOC
(function(){
  const toc = document.getElementById('toc-list');
  if(!toc) return;
  const article = document.querySelector('.article');
  if(!article) return;
  const headings = article.querySelectorAll('h2, h3');
  if(headings.length === 0){ const card = toc.closest('.right-card'); if(card) card.style.display='none'; return; }
  let html = '';
  headings.forEach(h => {
    if(!h.id) h.id = slugify(h.textContent);
    const cls = h.tagName === 'H3' ? ' class="toc-h3"' : '';
    const cleanText = h.textContent.replace(/\s+Common Roll|\s+Uncommon Roll|\s+Rare Roll|\s+Epic Roll|\s+Legendary Roll|\s+Mythical.*/g,'').trim();
    html += `<li><a href="#${h.id}"${cls}>${cleanText}</a></li>`;
  });
  toc.innerHTML = html;
  const links = toc.querySelectorAll('a');
  const obs = new IntersectionObserver(entries => {
    entries.forEach(en => {
      if(en.isIntersecting){
        links.forEach(a=>a.classList.remove('active'));
        const active = toc.querySelector(`a[href="#${en.target.id}"]`);
        if(active) active.classList.add('active');
      }
    });
  }, { rootMargin: '-80px 0px -65% 0px' });
  headings.forEach(h => obs.observe(h));
})();

// Copy code buttons - auto inject for code cards
function injectCodeCopyButtons(){
  document.querySelectorAll('.code-card .code-string').forEach(el => {
    const header = el.closest('.code-header');
    if(!header || header.querySelector('.code-copy-btn')) return;
    const btn = document.createElement('button');
    btn.className = 'code-copy-btn';
    btn.textContent = 'Copy';
    btn.dataset.code = el.textContent.trim();
    const badge = header.querySelector('.badge-new');
    if(badge) badge.before(btn);
    else header.appendChild(btn);
  });
}
injectCodeCopyButtons();

// Copy handler
document.addEventListener('click', e => {
  const btn = e.target.closest('.btn-copy, .code-copy-btn');
  if(!btn) return;
  const code = btn.dataset.code || btn.parentElement.querySelector('.code-string')?.textContent;
  if(!code) return;
  navigator.clipboard.writeText(code).then(()=>{
    const old = btn.textContent;
    btn.textContent = 'Copied!';
    setTimeout(()=> btn.textContent = old, 1200);
  });
});

// Mobile sidebar toggle
const sidebarToggle = document.getElementById('sidebar-toggle');
if(sidebarToggle){
  sidebarToggle.addEventListener('click', ()=>{
    document.getElementById('sidebar-left').classList.toggle('open');
  });
}

// Keyboard shortcut: / to focus search
document.addEventListener('keydown', e => {
  if((e.key === '/' && !['INPUT','TEXTAREA'].includes(document.activeElement.tagName)) || (e.ctrlKey && e.key.toLowerCase()==='k')){
    e.preventDefault();
    const si = document.getElementById('wiki-search');
    if(si){ si.focus(); si.select(); }
  }
});

// If page loaded with a #hash (from search), highlight the target row
window.addEventListener('load', () => {
  if(location.hash) {
    const target = document.querySelector(location.hash);
    if(target) {
      target.style.transition = 'background 0.3s';
      target.style.background = 'rgba(16,185,129,0.08)';
      target.scrollIntoView({behavior:'smooth', block:'center'});
      setTimeout(()=> target.style.background = '', 2000);
    }
  }
});
